(window.webpackJsonp=window.webpackJsonp||[]).push([[1318],{1232:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> arrayNesting = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> uf=[],weight=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums.length;i++){\\n    uf[i]=i\\n    weight[i]=<span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">find</span>(<span class=\\"hljs-params\\">i</span>)</span>{\\n    <span class=\\"hljs-keyword\\">while</span>(i!==uf[i]){\\n      i=uf[i]\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> i\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">union</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> i=find(a),\\n        j=find(b)\\n    <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">if</span>(weight[i]&lt;weight[j]){\\n      weight[j]+=weight[i]\\n      uf[i]=j\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      weight[i]+=weight[j]\\n      uf[j]=i\\n    }\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">isConnect</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> i=find(a),\\n        j=find(b)\\n    <span class=\\"hljs-keyword\\">return</span> i===j\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> id=i\\n    <span class=\\"hljs-keyword\\">while</span>(!isConnect(id,nums[id])){\\n      union(id,nums[id])\\n      id=nums[id]\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.max.apply(<span class=\\"hljs-built_in\\">Math</span>,weight)\\n};\\n</code></pre>\\n"],"titleSlug":"array-nesting","hasThinking":false,"content":"<p>\u7d22\u5f15\u4ece<code>0</code>\u5f00\u59cb\u957f\u5ea6\u4e3a<code>N</code>\u7684\u6570\u7ec4<code>A</code>\uff0c\u5305\u542b<code>0</code>\u5230<code>N - 1</code>\u7684\u6240\u6709\u6574\u6570\u3002\u627e\u5230\u6700\u5927\u7684\u96c6\u5408<code>S</code>\u5e76\u8fd4\u56de\u5176\u5927\u5c0f\uff0c\u5176\u4e2d <code>S[i] = {A[i], A[A[i]], A[A[A[i]]], ... }</code>\u4e14\u9075\u5b88\u4ee5\u4e0b\u7684\u89c4\u5219\u3002</p>\\n\\n<p>\u5047\u8bbe\u9009\u62e9\u7d22\u5f15\u4e3a<code>i</code>\u7684\u5143\u7d20<code>A[i]</code>\u4e3a<code>S</code>\u7684\u7b2c\u4e00\u4e2a\u5143\u7d20\uff0c<code>S</code>\u7684\u4e0b\u4e00\u4e2a\u5143\u7d20\u5e94\u8be5\u662f<code>A[A[i]]</code>\uff0c\u4e4b\u540e\u662f<code>A[A[A[i]]]...</code> \u4ee5\u6b64\u7c7b\u63a8\uff0c\u4e0d\u65ad\u6dfb\u52a0\u76f4\u5230<code>S</code>\u51fa\u73b0\u91cd\u590d\u7684\u5143\u7d20\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b&nbsp;1:</strong></p>\\n\\n<pre><strong>\u8f93\u5165:</strong> A = [5,4,0,3,1,6,2]\\n<strong>\u8f93\u51fa:</strong> 4\\n<strong>\u89e3\u91ca:</strong> \\nA[0] = 5, A[1] = 4, A[2] = 0, A[3] = 3, A[4] = 1, A[5] = 6, A[6] = 2.\\n\\n\u5176\u4e2d\u4e00\u79cd\u6700\u957f\u7684 S[K]:\\nS[0] = {A[0], A[5], A[6], A[2]} = {5, 6, 2, 0}\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ol>\\n\\t<li><code>N</code>\u662f<code>[1, 20,000]</code>\u4e4b\u95f4\u7684\u6574\u6570\u3002</li>\\n\\t<li><code>A</code>\u4e2d\u4e0d\u542b\u6709\u91cd\u590d\u7684\u5143\u7d20\u3002</li>\\n\\t<li><code>A</code>\u4e2d\u7684\u5143\u7d20\u5927\u5c0f\u5728<code>[0, N-1]</code>\u4e4b\u95f4\u3002</li>\\n</ol>\\n","title":"565. \u6570\u7ec4\u5d4c\u5957","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"565"}')}}]);